```javascript
const validateQueryParams = (req, res, next) => {
  // Validate query parameters
  if (req.query && Object.keys(req.query).length > 0) {
    const allowedParams = ['limit', 'page', 'sort'];
    const invalidParams = Object.keys(req.query).filter(param => !allowedParams.includes(param));

    if (invalidParams.length > 0) {
      return res.status(400).json({ 
        error: `Invalid query parameters: ${invalidParams.join(', ')}` 
      });
    }

    // Validate parameter values
    if (req.query.limit && (!Number.isInteger(Number(req.query.limit)) || Number(req.query.limit) > 100)) {
      return res.status(400).json({ 
        error: 'Limit must be an integer between 1 and 100' 
      });
    }
  }
  next();
};

// Apply validation to routes
app.get('/users', validateQueryParams, (req, res) => {
  // Process with validated input
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

### 2. Information Disclosure

The health check endpoint exposes the server's timestamp, which could potentially aid in certain types of attacks:

