# Security Recommendations for app.js

## 1. Input Validation
Always validate and sanitize user inputs. Even though current endpoints don't use parameters, future extensions could be vulnerable.

```javascript
const express = require('express');
const validator = require('validator');

// Example of input validation middleware
const validateUserId = (req, res, next) => {
  const userId = req.params.id;

  // Validate that userId is a positive integer
  if (!userId || !/^[1-9]\d*$/.test(userId)) {
    return res.status(400).json({
      error: 'Invalid user ID format'
    });
  }
  next();
};
```

## 2. Security Headers
Use Helmet.js to set security headers:

```javascript
const express = require('express');
const helmet = require('helmet');

const app = express();
// Apply security headers
app.use(helmet());
// More specific configuration
app.use(helmet.contentSecurityPolicy({
  directives: {
    defaultSrc: ["'self'"]
  }
}));
```

## 3. Rate Limiting
Protect against brute force and DDoS attacks:

```javascript
const rateLimit = require('express-rate-limit');

const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: {
    error: 'Too many requests from this IP, please try again later.'
  }
});

// Apply to all API routes
app.use('/api/', apiLimiter);
```

## 4. Proper Error Handling

```javascript
// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({
    error: 'Something went wrong!'
  });
});

// Handle 404
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found'
  });
});
```

## 5. Authentication for Sensitive Data

```javascript
const jwt = require('express-jwt');

// Protect users endpoint
const authenticate = jwt({
  secret: process.env.JWT_SECRET,
  algorithms: ['HS256']
});

app.get('/users', authenticate, (req, res) => {
  // Only accessible with valid token
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

## 6. Secure Health Check

```javascript
app.get('/health', (req, res) => {
  // Remove detailed information from health checks in production
  if (process.env.NODE_ENV === 'production') {
    res.json({ status: 'ok' });
  } else {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  }
});
```

## 7. Server Configuration Security

```javascript
const express = require('express');
const app = express();

// Security best practices for server configuration
app.set('trust proxy', 1); // Enable if behind a reverse proxy

// Remove powered-by header
app.disable('x-powered-by');

// Limit request size to prevent abuse
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```

## 8. Complete Secure Application Example

```javascript
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security middleware
app.use(helmet());
app.disable('x-powered-by');

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100
});
app.use(limiter);

// Body parsing with size limits
app.use(express.json({ limit: '10kb' }));

// Health check (minimal information)
app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});

// Error handling
app.use('*', (req, res) => {
  res.status(404).json({ error: 'Route not found' });
});

app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: 'Something went wrong!' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

