const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');

const app = express();

// Security middleware
app.use(helmet()); // Sets various HTTP headers for security

// CORS configuration
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS || 'https://yourdomain.com',
  credentials: true
}));

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});
app.use(limiter);

// Body parsing with limits to prevent abuse
app.use(express.json({
  limit: '10kb'
}));

// Input sanitization middleware
const sanitizeInput = (req, res, next) => {
  // Simple input sanitization
  if (req.query) {
    Object.keys(req.query).forEach(key => {
      if (typeof req.query[key] === 'string') {
        req.query[key] = req.query[key].replace(/[<>"'()]/g, '');
      }
    });
  }
  next();
};
app.use(sanitizeInput);

// Health check endpoint
app.get('/health', (req, res) => {
  // Add cache control for health checks
  res
    .set('Cache-Control', 'no-store')
    .json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
});

// Users endpoint with proper validation
app.get('/users', (req, res) => {
  // Validate query parameters if present
  const page = req.query.page ? parseInt(req.query.page) : 1;
  const limit = req.query.limit ? parseInt(req.query.limit) : 10;

  // Basic validation
  if (page < 1 || limit < 1 || limit > 100) {
    return res.status(400).json({
      error: 'Invalid pagination parameters'
    });
  }

  // In a real application, this would query a database
  // with proper parameterized queries to prevent SQL injection
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json({
    data: users,
    pagination: {
      page,
      limit,
      total: 2,
      pages: Math.ceil(2 / limit)
    }
  });
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found'
  });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Server error:', err);
  res.status(500).json({
    error: 'Internal server error'
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

